class Solution:
    def mostCommonWord(self, paragraph, banned):
        banned_set = set(b.lower() for b in banned)
        word = ''
        counts = {}
        for ch in paragraph + ' ':
            if ch.isalpha():
                word += ch.lower()
            else:
                if word and word not in banned_set:
                    counts[word] = counts.get(word, 0) + 1
                word = ''
        best = None
        best_c = -1
        for w, c in counts.items():
            if c > best_c:
                best_c = c
                best = w
        return best

